import{p as t,bh as i,I as c,U as h}from"./chunks/framework.BpabEsSf.js";const s=JSON.parse('{"title":"Autofill Modes & Fallback Mechanics","description":"","frontmatter":{"title":"Autofill Modes & Fallback Mechanics","date":"2026-05-16T14:15:00.000Z","permalink":"/reference/autofill","categories":["User Guides"],"tags":["Android","Autofill"]},"headers":[],"relativePath":"vi/02.Configuration/02.Docs/03.Monica-Android-Autofill Modes & Fallback Mechanics.md","filePath":"vi/02.Configuration/02.Docs/03.Monica-Android-Autofill Modes & Fallback Mechanics.md","lastUpdated":null}'),a={name:"vi/02.Configuration/02.Docs/03.Monica-Android-Autofill Modes & Fallback Mechanics.md"};function o(l,n,e,g,u,r){return i(),c("div",null,[...n[0]||(n[0]=[h('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /vi\\02.Configuration\\02.Docs\\03.Monica-Android-Autofill Modes &amp; Fallback Mechanics.md for this page in Markdown format</div><h1 id="⌨️-cac-phuong-thuc-tu-đong-đien-monica-android" tabindex="-1">⌨️ Các phương thức tự động điền Monica Android <a class="header-anchor" href="#⌨️-cac-phuong-thuc-tu-đong-đien-monica-android" aria-label="Permalink to &quot;⌨️ Các phương thức tự động điền Monica Android&quot;">​</a></h1><div class="note custom-block"><p class="title note-title custom-block-title">Tổng quan</p><p>Để ngăn ngừa các trường hợp quy trình tự động điền bị thất bại do các đặc tính riêng của hệ thống hoặc vấn đề tương thích với ứng dụng bên thứ ba, Monica for Android cung cấp ba phương thức tự động điền độc lập kết hợp với một cơ chế hạ cấp dự phòng cuối cùng (failsafe fallback). Cấu trúc đường ray kép này đảm bảo người dùng có thể thực hiện nhập thông tin xác thực một cách mượt mà dưới bất kỳ quy trình làm việc di động nào.</p></div><hr><h2 id="🛠️-ba-phuong-thuc-tu-đong-đien-chinh" tabindex="-1">🛠️ Ba phương thức tự động điền chính <a class="header-anchor" href="#🛠️-ba-phuong-thuc-tu-đong-đien-chinh" aria-label="Permalink to &quot;🛠️ Ba phương thức tự động điền chính&quot;">​</a></h2><h3 id="_1-tu-đong-đien-he-thong-tieu-chuan-standard-system-autofill" tabindex="-1">1. Tự động điền hệ thống tiêu chuẩn (Standard System Autofill) <a class="header-anchor" href="#_1-tu-đong-đien-he-thong-tieu-chuan-standard-system-autofill" aria-label="Permalink to &quot;1. Tự động điền hệ thống tiêu chuẩn (Standard System Autofill)&quot;">​</a></h3><ul><li><strong>Nguyên lý cốt lõi</strong>: Tận dụng khung cấu trúc Tự động điền (Autofill Framework) tiêu chuẩn của kiến trúc Android để phát hiện và khớp nối các trường nhập liệu mật khẩu.</li><li><strong>Cách kích hoạt</strong>: Di chuyển đến cài đặt hệ thống của thiết bị và chọn <code>Monica autofill</code> làm nhà cung cấp dịch vụ khung tự động điền toàn cục đang hoạt động.</li></ul><h3 id="_2-ban-phim-tuy-chinh-monica-monica-custom-keyboard" tabindex="-1">2. Bàn phím tùy chỉnh Monica (Monica Custom Keyboard) <a class="header-anchor" href="#_2-ban-phim-tuy-chinh-monica-monica-custom-keyboard" aria-label="Permalink to &quot;2. Bàn phím tùy chỉnh Monica (Monica Custom Keyboard)&quot;">​</a></h3><ul><li><strong>Nguyên lý cốt lõi</strong>: Hoạt động tương tự như một phương thức nhập liệu (IME) mềm độc lập chuyên dụng cho quản lý mật khẩu. Người dùng tiêu điểm vào ô nhập liệu mục tiêu, chạm vào mục nhập kích hoạt trên bố cục bàn phím tùy chỉnh, và sử dụng phím điều khiển <kbd>Tab</kbd> để chuyển đổi nhanh qua các trường và thả tuần tự các biến dữ liệu.</li><li><strong>Cách kích hoạt</strong>: Truy cập vào cài đặt Bàn phím ảo cấp hệ thống và bật hộp kiểm để kích hoạt công cụ nhập liệu <code>Monica Keyboard</code>.</li></ul><h3 id="_3-o-cai-đat-nhanh-quick-settings-ho-tro-tiep-can-accessibility" tabindex="-1">3. Ô cài đặt nhanh Quick Settings (Hỗ trợ tiếp cận - Accessibility) <a class="header-anchor" href="#_3-o-cai-đat-nhanh-quick-settings-ho-tro-tiep-can-accessibility" aria-label="Permalink to &quot;3. Ô cài đặt nhanh Quick Settings (Hỗ trợ tiếp cận - Accessibility)&quot;">​</a></h3><ul><li><strong>Nguyên lý cốt lõi</strong>: Khai thác các nguyên mẫu dịch vụ Hỗ trợ tiếp cận của Android (Android Accessibility Services) để ép tiêm các chuỗi ký tự vào cây bố cục (layout tree) đang hoạt động. Đây là tuyến đường dự phòng thứ hai khi các trình lắng nghe khung tiêu chuẩn bị chặn hoặc ức chế.</li><li><strong>Cách kích hoạt</strong>: Chỉnh sửa bảng Cài đặt nhanh (Quick Settings) của thiết bị để thêm phím tắt Monica Tile, sau đó cấp quyền cho <code>Monica Pass</code> trong menu định nghĩa Dịch vụ hỗ trợ tiếp cận của hệ thống.</li></ul><hr><h2 id="🛡️-co-che-ha-cap-du-phong-cuoi-cung-ultimate-failsafe-fallback" tabindex="-1">🛡️ Cơ chế hạ cấp dự phòng cuối cùng (Ultimate Failsafe Fallback) <a class="header-anchor" href="#🛡️-co-che-ha-cap-du-phong-cuoi-cung-ultimate-failsafe-fallback" aria-label="Permalink to &quot;🛡️ Cơ chế hạ cấp dự phòng cuối cùng (Ultimate Failsafe Fallback)&quot;">​</a></h2><p>Nếu tất cả ba con đường tự động hóa chính ở trên đều bị chặn do các giới hạn môi trường nghiêm trọng của ứng dụng mục tiêu, bạn có thể triển khai một cầu nối tiêm thủ công mạnh mẽ kết hợp giữa <strong>Ô cài đặt nhanh (Quick Settings Tile)</strong> và trình lắng nghe <strong>Engine thông báo (Notification Engine)</strong>.</p><h3 id="đuong-dan-cau-hinh" tabindex="-1">Đường dẫn cấu hình: <a class="header-anchor" href="#đuong-dan-cau-hinh" aria-label="Permalink to &quot;Đường dẫn cấu hình:&quot;">​</a></h3><ul><li>Đưa phím tắt lối tắt tùy chỉnh vào bảng kéo xuống Cài đặt nhanh phần cứng của bạn.</li><li>Cấp cho <code>Monica Pass</code> quyền <strong>Thông báo tuyệt đối (Notification Permissions)</strong> trong cài đặt ứng dụng Android.</li></ul><h3 id="cac-buoc-thuc-hien" tabindex="-1">Các bước thực hiện: <a class="header-anchor" href="#cac-buoc-thuc-hien" aria-label="Permalink to &quot;Các bước thực hiện:&quot;">​</a></h3><ol><li>Kéo thanh thông báo hệ thống xuống và chạm vào <strong>Monica Tile</strong> để kích hoạt một giao diện lớp phủ (overlay) danh sách kho mật khẩu của bạn.</li><li>Tìm và chạm vào mục thông tin xác thực bạn cần, sau đó chọn <strong>&quot;Sao chép tên người dùng &amp; Đưa mật khẩu vào hàng đợi thông báo&quot;</strong>.</li><li>Hệ thống runtime sẽ ngay lập tức sao chép chuỗi tài khoản vào clipboard toàn cục của bạn, đồng thời ghim một mục thông báo vào thanh trạng thái.</li><li>Dán tài khoản vào trường nhập liệu của biểu mẫu, <strong>kéo thanh thông báo xuống một lần nữa và nhấp vào khối thông báo Monica được ghim</strong>. Hành động này sẽ kích hoạt một trình lắng nghe để sao chép chuỗi mật khẩu tương ứng vào clipboard, cho phép bạn triển khai ngay lập tức cho trường còn lại.</li></ol>',18)])])}const m=t(a,[["render",o]]);export{s as __pageData,m as default};
